import unicodedata
def soft_eq(a, b):
    return unicodedata.normalize("NFC", a).casefold() == unicodedata.normalize("NFC", b).casefold()
print(soft_eq("José", "JOSE\u0301"))
print(soft_eq("Ana", "Luis"))

def parse_name(raw):
    toks = " ".join(raw.split()).split()
    if len(toks) < 2:
        return {"status": "review", "raw": raw, "given": None, "ap1": None, "ap2": None}
    return {"status": "ok", "raw": raw, "given": " ".join(toks[:-2]) if len(toks)>2 else toks[0],
            "ap1": toks[-2] if len(toks)>=2 else None, "ap2": toks[-1]}
print(parse_name("Luis"))
print(parse_name("Ana Quispe Huamán"))

def normalize_email(raw: str) -> str:
    s = raw.strip().casefold()
    if s.count("@") != 1 or any(ch.isspace() for ch in s):
        raise ValueError("email requiere un @ y cero espacios")
    local, domain = s.split("@")
    if not local or not domain:
        raise ValueError("email requiere local y dominio")
    return s
print(normalize_email("  Ana@Ex.com "))

def normalize_phone_pe(raw: str) -> str:
    return "".join(ch for ch in raw if ch.isdigit())
print(normalize_phone_pe("999-000-111"))
print(len(normalize_phone_pe("999-000-111")) == 9)

def normalize_pair(email, phone):
    e = email.strip().casefold()
    p = "".join(c for c in phone if c.isdigit())
    return {"email": e, "phone": p}
print(normalize_pair("  X@Y.COM ", "(999) 111 222"))

def token_jaccard(a: str, b: str) -> float:
    A = set(a.replace(".", " ").casefold().split())
    B = set(b.replace(".", " ").casefold().split())
    if not A and not B:
        return 1.0
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)
s = token_jaccard("Juan Perez", "Juan P. Perez")
print("score", round(s, 3))
print("decision", "review" if 0.4 <= s < 1.0 else ("exact" if s == 1.0 else "no_match"))

def token_jaccard(a, b):
    A, B = set(a.casefold().split()), set(b.casefold().split())
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)
print(round(token_jaccard("Ana Quispe", "Ana Q. Quispe"), 3))
